import type { Metadata, Viewport } from "next";
import { Inter, Fredoka } from "next/font/google";
import "./globals.css";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-sans",
  display: "swap",
});

const fredoka = Fredoka({
  subsets: ["latin"],
  variable: "--font-display",
  display: "swap",
});

export const metadata: Metadata = {
  metadataBase: new URL("https://example.com"),
  title: {
    default: "Checkers Arena",
    template: "%s • Checkers Arena",
  },
  description:
    "A polished, fun checkers experience with local play, online-ready scaffolding, timers, hints, undo/redo, and long-term stats tracking.",
  applicationName: "Checkers Arena",
  keywords: [
    "checkers",
    "draughts",
    "next.js",
    "board game",
    "strategy",
    "multiplayer",
  ],
  openGraph: {
    title: "Checkers Arena",
    description:
      "A modern, responsive checkers game shell built for local multiplayer, AI, and online-ready extensions.",
    type: "website",
  },
  twitter: {
    card: "summary_large_image",
    title: "Checkers Arena",
    description:
      "A modern, responsive checkers game shell built for local multiplayer, AI, and online-ready extensions.",
  },
  robots: {
    index: true,
    follow: true,
  },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  maximumScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: light)", color: "#e8ecf7" },
    { media: "(prefers-color-scheme: dark)", color: "#0b1220" },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const currentYear = new Date().getFullYear();

  return (
    <html lang="en" suppressHydrationWarning>
      <body className={`${inter.variable} ${fredoka.variable}`}>
        <a className="skip-link" href="#main-content">
          Skip to main content
        </a>

        <div className="app-root" data-theme="dark-modern">
          <div className="app-bg" aria-hidden="true" />

          <header className="app-header">
            <div className="shell-container">
              <div>
                <p className="eyebrow">Ready for match day</p>
                <h1 className="brand">Checkers Arena</h1>
              </div>
              <p className="tagline">
                Fast turns, smart strategy, and playful competition.
              </p>
            </div>
          </header>

          <main id="main-content" className="app-main">
            <div className="shell-container">{children}</div>
          </main>

          <footer className="app-footer">
            <div className="shell-container footer-row">
              <p>Built for local multiplayer, AI, puzzles, and online expansion.</p>
              <p className="footer-meta">© {currentYear} Checkers Arena</p>
            </div>
          </footer>
        </div>
      </body>
    </html>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --font-sans: "Inter", ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto,
    Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol";
  --font-display: "Fredoka", var(--font-sans);

  --radius-sm: 10px;
  --radius-md: 14px;
  --radius-lg: 20px;
  --radius-xl: 28px;

  --shadow-sm: 0 4px 20px rgb(0 0 0 / 0.16);
  --shadow-md: 0 12px 32px rgb(0 0 0 / 0.24);
  --shadow-lg: 0 24px 60px rgb(0 0 0 / 0.35);

  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-10: 2.5rem;
  --space-12: 3rem;

  --bg: #0b1220;
  --bg-soft: #111b2f;
  --surface: #14233c;
  --surface-2: #1a2e4f;
  --line: #314868;
  --text: #ebf2ff;
  --text-dim: #afc0de;
  --primary: #6de2ff;
  --primary-strong: #37c9ff;
  --accent: #8b5cf6;
  --success: #36d399;
  --warning: #f6c760;
  --danger: #f87272;
}

/* Theme-ready primitives for future game settings */
[data-theme="playful-colorful"] {
  --bg: #140d2e;
  --bg-soft: #1d1140;
  --surface: #271852;
  --surface-2: #311f63;
  --line: #5d4a9d;
  --text: #f4efff;
  --text-dim: #cabff8;
  --primary: #4de7ff;
  --primary-strong: #00c7f5;
  --accent: #ff7cc8;
}

[data-theme="classic-wooden"] {
  --bg: #19130d;
  --bg-soft: #241a11;
  --surface: #322316;
  --surface-2: #42301f;
  --line: #6d5439;
  --text: #f7efe3;
  --text-dim: #cfbea7;
  --primary: #f3b562;
  --primary-strong: #e59f45;
  --accent: #b6d28a;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
}

body {
  font-family: var(--font-sans);
  color: var(--text);
  background: var(--bg);
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

img,
svg,
video,
canvas {
  display: block;
  max-width: 100%;
}

.skip-link {
  position: fixed;
  top: -100%;
  left: var(--space-4);
  z-index: 1000;
  background: var(--surface-2);
  color: var(--text);
  border: 1px solid var(--primary);
  border-radius: var(--radius-sm);
  padding: var(--space-2) var(--space-4);
  transition: top 180ms ease;
}

.skip-link:focus {
  top: var(--space-4);
}

.app-root {
  position: relative;
  min-height: 100dvh;
  isolation: isolate;
  overflow: clip;
}

.app-bg {
  position: absolute;
  inset: 0;
  z-index: -1;
  background:
    radial-gradient(900px 500px at 5% -5%, color-mix(in oklab, var(--primary) 22%, transparent), transparent 65%),
    radial-gradient(700px 450px at 100% 0%, color-mix(in oklab, var(--accent) 25%, transparent), transparent 70%),
    linear-gradient(180deg, var(--bg-soft), var(--bg));
}

.shell-container {
  width: min(1120px, calc(100% - 2rem));
  margin-inline: auto;
}

.app-header {
  position: sticky;
  top: 0;
  z-index: 20;
  backdrop-filter: blur(10px);
  background: color-mix(in oklab, var(--bg) 78%, transparent);
  border-bottom: 1px solid color-mix(in oklab, var(--line) 72%, transparent);
}

.app-header .shell-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-6);
  padding-block: var(--space-4);
}

.eyebrow {
  margin: 0;
  font-size: 0.75rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-dim);
}

.brand {
  margin: 0.1rem 0 0;
  font-family: var(--font-display);
  font-size: clamp(1.45rem, 2.2vw, 1.9rem);
  line-height: 1.1;
}

.tagline {
  margin: 0;
  max-width: 40ch;
  color: var(--text-dim);
  text-align: right;
  font-size: 0.94rem;
}

.app-main {
  padding-block: clamp(1rem, 2vw, 2rem) clamp(2.5rem, 5vw, 4rem);
}

.app-footer {
  border-top: 1px solid color-mix(in oklab, var(--line) 70%, transparent);
  background: color-mix(in oklab, var(--bg) 86%, transparent);
}

.footer-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-5);
  color: var(--text-dim);
  font-size: 0.9rem;
  padding-block: var(--space-4) var(--space-6);
}

.footer-meta {
  white-space: nowrap;
}

/* Reusable primitives for upcoming feature work */
.card {
  background: linear-gradient(180deg, var(--surface), var(--surface-2));
  border: 1px solid color-mix(in oklab, var(--line) 75%, transparent);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
}

.btn {
  appearance: none;
  border: 1px solid color-mix(in oklab, var(--line) 85%, transparent);
  background: var(--surface);
  color: var(--text);
  border-radius: 999px;
  padding: 0.6rem 1rem;
  font: inherit;
  font-weight: 600;
  cursor: pointer;
  transition: transform 120ms ease, background-color 160ms ease, border-color 160ms ease,
    box-shadow 180ms ease;
}

.btn:hover {
  transform: translateY(-1px);
  border-color: color-mix(in oklab, var(--primary) 55%, var(--line));
}

.btn:active {
  transform: translateY(0);
}

.btn:focus-visible {
  outline: 2px solid color-mix(in oklab, var(--primary) 80%, white);
  outline-offset: 2px;
}

.btn-primary {
  background: linear-gradient(135deg, var(--primary), var(--primary-strong));
  border-color: transparent;
  color: #031018;
  box-shadow: 0 8px 24px color-mix(in oklab, var(--primary) 35%, transparent);
}

.input,
.select,
.textarea {
  width: 100%;
  border: 1px solid color-mix(in oklab, var(--line) 85%, transparent);
  background: color-mix(in oklab, var(--surface) 86%, black 14%);
  color: var(--text);
  border-radius: var(--radius-md);
  padding: 0.7rem 0.85rem;
  font: inherit;
  transition: border-color 150ms ease, box-shadow 180ms ease;
}

.input:focus,
.select:focus,
.textarea:focus {
  border-color: color-mix(in oklab, var(--primary) 65%, var(--line));
  box-shadow: 0 0 0 4px color-mix(in oklab, var(--primary) 18%, transparent);
  outline: none;
}

@media (max-width: 768px) {
  .app-header .shell-container,
  .footer-row {
    flex-direction: column;
    align-items: flex-start;
  }

  .tagline {
    text-align: left;
    max-width: unset;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}
